export const vilniusSpots = [
  { id:'vilnius-uzupis', name:'Užupis', city:'Vilnius', country:'Lithuania', shortDesc:'Independent micro-republic in Vilnius with its own constitution and army of 11', fullDesc:'A bohemian neighbourhood that declared independence from Lithuania in 1997, with its own president, army of 11, national anthem and constitution (translated into 60 languages and displayed on mirrored plaques). The Republic of Užupis celebrates its independence day on April 1 and attracts artists, musicians and philosophers.', whyHidden:'Requires crossing the Vilnelė river from the old city. The concept — a self-declared republic — sounds gimmicky but the neighbourhood is genuinely extraordinary.', bestTime:'April 1 (Independence Day); any day to read the constitution plaques', howToGet:'Walk east from the Cathedral through the old city to the Užupis bridge.', whatToAvoid:'Nothing — the neighbourhood is small and walkable', hiddennessScore:5, category:'Neighbourhood', interests:['art','unusual','photography'], lat:54.6796, lng:25.2961, address:'Užupis, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-literatu-street', name:'Literatų Gatvė (Literature Street)', city:'Vilnius', country:'Lithuania', shortDesc:'A street with 200 ceramic tiles honouring Lithuanian writers — extraordinary public art', fullDesc:'A short street in the old city covered with over 200 ceramic portrait tiles honouring Lithuanian writers and poets, created by artists and placed on the walls since 2008. The cumulative effect of 200 portraits on a single street is extraordinary and unlike any other public art installation in Europe.', whyHidden:'On a side street in the old city — easy to miss without knowing to look for it. The tiles are small and individual; the cumulative effect takes time to absorb.', bestTime:'Any day in good light', howToGet:'Walk from Cathedral Square along Pilies Street, turn left at Literatų Gatvė.', whatToAvoid:'Nothing — the street is always accessible', hiddennessScore:6, category:'Art', interests:['art','photography'], lat:54.6835, lng:25.2888, address:'Literatų Gatvė, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-st-peter-paul-church', name:'St. Peter and Paul Church', city:'Vilnius', country:'Lithuania', shortDesc:'2000 white stucco figures cover every surface — the most extraordinary baroque interior in the Baltics', fullDesc:'An early baroque church on Antakalnis hill completed in 1701, its interior encrusted with over 2000 white stucco figures created by Italian sculptors Gian Pietro Perti and Giovanni Maria Galli. Apostles, angels, animals, battle scenes and allegorical figures cover every centimetre of wall, vault and pillar. Nothing in Northern or Eastern Europe compares.', whyHidden:'Located 2km north of the old city along Antakalnio Street — far enough to deter casual tourists who stay within the old town. Unknown to almost all visitors despite being a European masterpiece.', bestTime:'Morning when side light rakes across the stucco figures', howToGet:'Bus 2 or 3 from Cathedral Square to Antakalnis, then walk; or a 25-minute walk north along Antakalnio gatve.', whatToAvoid:'No photography during Mass; evening services close the nave', hiddennessScore:7, category:'Spiritual', interests:['monuments','photography','art'], lat:54.6942, lng:25.2819, address:'Antakalnio g. 1, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-gates-of-dawn', name:'Gates of Dawn (Aušros Vartai)', city:'Vilnius', country:'Lithuania', shortDesc:'Only surviving city gate houses a miraculous 16th-century Madonna icon above the arch', fullDesc:'The sole remaining gate of the original city wall, with a chapel built above the arch containing a silver-clad icon of the Madonna of Mercy venerated as miraculous since 1671. Pilgrims climb stairs inside the gate to pray in the chapel; the street below passes directly under the icon. One of the most visited religious sites in the Catholic world.', whyHidden:'Surprising how few tourists look up — the chapel and icon are above the archway. Walking through the gate, most people don\'t realise the chapel is accessible by the stairs on the left.', bestTime:'Early morning during weekday Mass when pilgrims fill the chapel stairs', howToGet:'Walk south through the old city along Aušros Vartų gatvė from the Town Hall.', whatToAvoid:'Large pilgrim groups on major Marian feast days; dress respectfully for the chapel', hiddennessScore:4, category:'Spiritual', interests:['monuments','photography','museums'], lat:54.6770, lng:25.2921, address:'Aušros Vartų g. 14, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-kgb-museum', name:'Museum of Occupations and Fights for Freedom', city:'Vilnius', country:'Lithuania', shortDesc:'The KGB\'s Vilnius headquarters intact — interrogation cells, execution room, all preserved', fullDesc:'The actual KGB headquarters of Soviet Lithuania, operating as a prison, interrogation centre and execution facility from 1940 to 1991. The building was handed over unchanged; prison cells, interrogation rooms, solitary confinement boxes and the execution basement are all preserved. The documentation of Soviet crimes against Lithuanians is comprehensive and profoundly moving.', whyHidden:'Looks like an ordinary Soviet administrative building from outside. Tourists on a brief Vilnius visit prioritise the old town; this museum — one of the most important in Europe — is consistently undervisited.', bestTime:'Weekday mornings when it is quiet; the experience demands concentrated attention', howToGet:'Walk west from Cathedral Square along Gedimino prospect for 10 minutes to number 40.', whatToAvoid:'Children under 12 — some exhibits are extremely disturbing', hiddennessScore:4, category:'Museum', interests:['museums','history'], lat:54.6881, lng:25.2748, address:'Gedimino pr. 40, Vilnius', entryPrice:'€8', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-paneriai-memorial', name:'Paneriai Memorial (Ponary)', city:'Vilnius', country:'Lithuania', shortDesc:'Forest pits where 100,000 Jews were murdered by Nazis in 1941–1944 — the most important site in Vilnius', fullDesc:'The forest of Paneriai, 10km southwest of Vilnius, contains the execution pits where the German Einsatzgruppen and Lithuanian collaborators murdered approximately 100,000 people — 70,000 of them Jewish residents of Vilnius — between 1941 and 1944. The mass graves are marked by modest memorials in the forest. A small museum documents what happened. One of the most significant Holocaust sites in Europe.', whyHidden:'Requires a suburban train to Paneriai station and a 20-minute walk through the forest. The site receives a fraction of the visitors of Auschwitz despite being comparably significant.', bestTime:'Weekday mornings for quiet contemplation', howToGet:'Train from Vilnius station (10 minutes) to Paneriai stop; follow signs through the forest.', whatToAvoid:'Photography of the mass grave pits is inappropriate — be respectful', hiddennessScore:8, category:'Museum', interests:['museums','history'], lat:54.6247, lng:25.1568, address:'Agrastų g. 17, Paneriai, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-university-courtyards', name:'Vilnius University Courtyards', city:'Vilnius', country:'Lithuania', shortDesc:'14 interconnected Baroque courtyards — the most beautiful university campus in Northern Europe', fullDesc:'Vilnius University, founded in 1579 by Jesuits, covers an entire block of the old city with 14 interconnected courtyards ranging from intimate Baroque gardens to the vast Great Courtyard. The Observatory Courtyard has a zodiac floor; the St. John\'s Church courtyard contains Lithuania\'s tallest tower. The complex is one of the finest pieces of urban architecture in Europe.', whyHidden:'The entrance on Universiteto gatvė is a single doorway. Most visitors see the exterior of the university\'s churches but never enter the courtyard labyrinth inside.', bestTime:'Weekday mornings during university term when students move between courtyards', howToGet:'Enter through the main gate on Universiteto gatvė 3, in the heart of the old town.', whatToAvoid:'Some courtyards are restricted during exams; entry fee for the St. John\'s Church tower', hiddennessScore:5, category:'Architecture', interests:['monuments','photography','art'], lat:54.6847, lng:25.2893, address:'Universiteto g. 3, Vilnius', entryPrice:'Free (tower €3)', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-gediminas-castle', name:'Gediminas Castle Tower', city:'Vilnius', country:'Lithuania', shortDesc:'Red-brick hilltop tower, founding monument of Lithuania — best panoramic view of the old city', fullDesc:'The sole surviving tower of Gediminas Castle, built in the 14th century on a hill above the old city. The tower houses a small museum of medieval armour and castle history; the rooftop offers the finest panorama of the old city and the confluence of the Vilnelė and Neris rivers. A flying Lithuanian flag is visible from every point in the old city.', whyHidden:'The hill is steep and the entrance less obvious than the tourist maps suggest. The museum inside is small but the rooftop view makes the climb entirely worthwhile.', bestTime:'Clear morning; sunset for the golden light on the old city rooftops', howToGet:'Walk up the hill from Cathedral Square via the funicular (or stairs on the south side).', whatToAvoid:'The funicular is often queued in summer; stairs take 10 minutes and are uncrowded', hiddennessScore:4, category:'Museum', interests:['museums','monuments','photography'], lat:54.6868, lng:25.2939, address:'Arsenalo g. 5, Vilnius', entryPrice:'€5', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-great-synagogue-site', name:'Great Synagogue of Vilna (Site)', city:'Vilnius', country:'Lithuania', shortDesc:'The greatest synagogue in Europe was demolished by the Nazis — its outline is marked in a schoolyard', fullDesc:'The Great Synagogue of Vilna, built in 1633 and one of the most magnificent Jewish buildings in the world, was looted and badly damaged by the Nazis and demolished in 1955 by the Soviets who built a primary school on the site. Archaeological excavations since 2015 have revealed the synagogue\'s foundations; the outline of the building is now marked in the schoolyard pavement.', whyHidden:'The Nazis destroyed the building so thoroughly that most visitors have no idea the greatest synagogue in Europe once stood here. The site requires knowing to look — there is no large monument.', bestTime:'Any weekday when the schoolyard is accessible', howToGet:'Walk into the courtyard of the primary school at Žydų gatvė 3, off Vokiečių gatvė.', whatToAvoid:'Closed in evenings and weekends when the school is shut', hiddennessScore:8, category:'Museum', interests:['history','monuments'], lat:54.6812, lng:25.2870, address:'Žydų g. 3, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-frank-zappa-statue', name:'Frank Zappa Bust', city:'Vilnius', country:'Lithuania', shortDesc:'The world\'s only authorised Frank Zappa bust — installed 1995 as an act of post-Soviet defiance', fullDesc:'A bronze bust of Frank Zappa mounted on a column in a courtyard off Kalinausko gatvė, installed in 1995. It is the only official Frank Zappa monument in the world. The choice of Zappa — patron saint of artistic freedom — as a symbol of post-Soviet independence was suggested by a Lithuanian diplomat. The bust was cast in the same mould as those in Kansas City and Cleveland.', whyHidden:'In a courtyard off a side street with no signage from the main road. The backstory — why Vilnius has the world\'s only Zappa bust — is one of the most interesting in the city.', bestTime:'Any time', howToGet:'Walk along Kalinausko gatvė from Vinco Kudirkos square; look for the courtyard entrance on the right.', whatToAvoid:'Nothing specific', hiddennessScore:7, category:'Offbeat', interests:['art','unusual','photography'], lat:54.6921, lng:25.2762, address:'Kalinausko g. 1, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-tv-tower', name:'Vilnius TV Tower and January 13 Memorial', city:'Vilnius', country:'Lithuania', shortDesc:'Soviet TV tower where 14 civilians were killed by tanks on January 13, 1991 — the moment Lithuania regained independence', fullDesc:'The 326-metre television tower built 1974–1980, now inseparable from the story of Lithuanian independence. On January 13, 1991, Soviet tanks and troops stormed the tower, killing 14 unarmed civilians who had formed a human shield. Their photographs are displayed at the base of the tower alongside the marks left by tank treads on the concrete. The observation deck at 165 metres has extraordinary views.', whyHidden:'In the Karoliniškes district, a long tram ride from the old city. The historical significance is immense but the location keeps it off most tourist itineraries.', bestTime:'Clear days for the view; January 13 (Freedom Defenders\' Day) for the memorial atmosphere', howToGet:'Tram 16 from the city centre to Televizijos bokštas stop.', whatToAvoid:'The rotating restaurant is expensive; the observation deck ticket is worthwhile', hiddennessScore:6, category:'Museum', interests:['museums','monuments','photography'], lat:54.6980, lng:25.2300, address:'Sausio 13-osios g. 10, Vilnius', entryPrice:'€9 observation deck', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-hales-market', name:'Halės Turgus', city:'Vilnius', country:'Lithuania', shortDesc:'Vilnius\'s 1906 iron-and-glass market hall — fresh produce, smoked fish, homemade cheese', fullDesc:'An Art Nouveau iron-and-glass market hall built in 1906, recently restored, selling fresh vegetables, local cheeses, smoked fish, rye bread, mushrooms and wild berries from local farms. The surrounding stalls spill onto the street outside. On weekends a flea market occupies the adjacent square.', whyHidden:'In the Užupis area — requires a short walk from the old town. The market is used entirely by local residents and looks forbidding from outside.', bestTime:'Saturday mornings for the fullest market and adjacent flea stalls', howToGet:'Walk east from Town Hall along Pylimo gatvė, then south to Pylimo 58.', whatToAvoid:'Closed Sunday afternoons; reduced stalls Monday–Tuesday', hiddennessScore:5, category:'Market', interests:['food','markets','photography'], lat:54.6777, lng:25.2958, address:'Pylimo g. 58, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-st-anne-church', name:'Church of St. Anne', city:'Vilnius', country:'Lithuania', shortDesc:'Gothic flame-brick facade Napoleon claimed to want to carry to Paris on his palm', fullDesc:'A late Gothic church completed around 1500, its facade a masterwork of flame-brick architecture with 33 distinct brick types woven into a pattern of Gothic pinnacles and tracery. Napoleon Bonaparte, passing through in 1812, allegedly said he wished to carry it back to Paris on his palm. The adjacent Bernardine Church, one of the largest Gothic buildings in Lithuania, forms a complex together with St. Anne\'s.', whyHidden:'At the end of the old city near Užupis — tourists see the famous view from the bridge but rarely enter or examine the facade closely. The Bernardine Church next door is almost always empty.', bestTime:'Morning for the best light on the facade; late afternoon when the brick glows', howToGet:'Walk east through the old city along Pilies gatvė to the end; turn right at the Bernardine Church.', whatToAvoid:'Sunday morning Mass creates crowds; the church is small and fills quickly', hiddennessScore:4, category:'Architecture', interests:['monuments','photography'], lat:54.6819, lng:25.2930, address:'Maironio g. 8, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-holy-spirit-church', name:'Church of the Holy Spirit', city:'Vilnius', country:'Lithuania', shortDesc:'Dominican church with incorrupt bodies of three patron saints on display — open daily', fullDesc:'A Baroque Dominican church behind the Gates of Dawn with an extraordinary high altar and, in the crypt beneath the main altar, the incorrupt bodies of three martyred saints — Casimir, Crispin and other companions — preserved in glass reliquaries. One of the most active Catholic pilgrimage sites in Lithuania.', whyHidden:'Directly behind the Gates of Dawn yet most visitors turn around after the Madonna chapel and miss this church entirely.', bestTime:'Weekday morning Mass (8am); or any quiet afternoon', howToGet:'Walk through the Gates of Dawn and immediately left — the church is 50 metres away.', whatToAvoid:'Dress modestly; photography restricted near the reliquaries', hiddennessScore:6, category:'Spiritual', interests:['monuments','photography'], lat:54.6772, lng:25.2917, address:'Dominikonų g. 8, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-st-nicholas-church', name:'Church of St. Nicholas', city:'Vilnius', country:'Lithuania', shortDesc:'The oldest surviving church in Vilnius — 14th-century Gothic brick, rarely visited', fullDesc:'The oldest surviving church in Vilnius, built in the 14th century in Gothic brick and barely altered since. One of only two Gothic brick churches remaining in the city. The interior is plain and atmospheric — whitewashed walls, Gothic arches, a single nave. The church served the German merchant community of medieval Vilnius.', whyHidden:'On a side street in the old city with no tourist infrastructure. The oldest building in Vilnius receives almost no visitors because it looks like any other old church.', bestTime:'Weekday mornings during the brief opening hours', howToGet:'Walk along Šv. Mikalojaus gatvė from Pilies gatvė.', whatToAvoid:'Irregular opening hours — check in advance', hiddennessScore:8, category:'Architecture', interests:['monuments','history'], lat:54.6788, lng:25.2899, address:'Šv. Mikalojaus g. 4, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-cac-contemporary-art', name:'Contemporary Art Centre (CAC)', city:'Vilnius', country:'Lithuania', shortDesc:'One of the best contemporary art venues in Eastern Europe — in a Soviet-era building', fullDesc:'Housed in a Soviet administrative building on Vokiečių gatvė, the Vilnius CAC has been one of the most significant contemporary art institutions in the post-Soviet space since the early 1990s. The programming combines Lithuanian artists with major international figures and the quality is consistently higher than the location and budget suggest.', whyHidden:'In a building that looks Soviet and anonymous. The contemporary art context doesn\'t fit the Baroque old city narrative, so it falls off most tourist itineraries.', bestTime:'Weekday afternoons; check the exhibition programme online', howToGet:'Walk along Vokiečių gatvė from the Town Hall; the CAC is at number 2.', whatToAvoid:'Closed Monday; some major exhibitions charge entry', hiddennessScore:6, category:'Art', interests:['art','museums'], lat:54.6804, lng:25.2879, address:'Vokiečių g. 2, Vilnius', entryPrice:'Free–€5', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-national-gallery', name:'National Gallery of Art', city:'Vilnius', country:'Lithuania', shortDesc:'Entire 20th-century Lithuanian art in Napoleonic barracks — almost always empty', fullDesc:'Housed in an early 19th-century Napoleonic-era barracks complex in the new town, the National Gallery of Art holds the comprehensive collection of Lithuanian art from 1900 to the present — including the extraordinary mystical paintings of M.K. Čiurlionis, Lithuania\'s greatest artist. The collection is among the finest in the Baltics and the building consistently quiet.', whyHidden:'In Naujamiestis, a neighbourhood tourists don\'t visit. The Čiurlionis paintings alone — vast symbolist canvases of dreamlike landscapes — are worth the tram ride from the old city.', bestTime:'Any weekday', howToGet:'Walk west along Gedimino prospect for 20 minutes, or tram 2/3 to Vincas Kudirka square.', whatToAvoid:'Closed Monday', hiddennessScore:6, category:'Art', interests:['art','museums','photography'], lat:54.6940, lng:25.2701, address:'Konstitucijos pr. 22, Vilnius', entryPrice:'€5', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-zverynas', name:'Žvėrynas Wooden Villas', city:'Vilnius', country:'Lithuania', shortDesc:'Island neighbourhood of early 20th-century wooden Art Nouveau villas — entirely residential, no tourists', fullDesc:'An island formed by a bend in the Neris river, covered with early 20th-century wooden villas in various states of preservation. The architecture ranges from Swiss chalet to Baltic vernacular to Art Nouveau; many are painted in original colours. The neighbourhood feels like a different era — quiet, domestic, car-sparse.', whyHidden:'Across the Neris from the old city and separated by the river on three sides. Requires a specific bus or 30-minute walk. No tourist infrastructure.', bestTime:'Spring and summer when the wooden houses glow in the greenery', howToGet:'Bus 15 from Cathedral Square over the Žvėrynas bridge; or walk along Čiurlionio gatvė.', whatToAvoid:'Nothing specific — residential streets, be quiet in the evenings', hiddennessScore:8, category:'Neighbourhood', interests:['photography','art'], lat:54.6943, lng:25.2530, address:'Žvėrynas, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-bernardine-garden', name:'Bernardine Garden', city:'Vilnius', country:'Lithuania', shortDesc:'Restored 19th-century riverside garden — Vilnius old city\'s best-kept green space', fullDesc:'A historic garden on the bank of the Vilnelė river between the Bernardine Church and the Užupis bridge, restored to its 19th-century design in 2013. The garden has formal paths, a fountain, sculptures of Lithuanian fairy tale characters and a small outdoor stage. It is the most pleasant place in the old city to sit on a warm day.', whyHidden:'Directly adjacent to St. Anne\'s Church and Užupis but consistently overlooked. Most tourists walk past the garden entrance without entering.', bestTime:'Warm evenings when local families use the benches; spring when cherry trees blossom', howToGet:'Walk east from the Cathedral to the Užupis bridge; the garden is on the right bank of the river.', whatToAvoid:'Can be muddy after rain', hiddennessScore:4, category:'Park', interests:['relaxation','photography'], lat:54.6800, lng:25.2960, address:'Maironio g., Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-vingio-park', name:'Vingis Park', city:'Vilnius', country:'Lithuania', shortDesc:'Largest park in Vilnius, with a 30,000-person open-air stage and kilometre-long tree avenues', fullDesc:'A large park in a bend of the Neris river with 150 hectares of deciduous forest, long cycling paths and a vast open-air amphitheatre — the Lithuanian Song Festival stage, which fills with 30,000 people every five years for the National Song Celebration. On ordinary days the park is used for jogging, cycling and dog-walking by the entire city.', whyHidden:'Across the Neris river from the old city — perceived as suburban. The scale of the Song Festival stage and the quality of the mature forest are extraordinary.', bestTime:'Summer evenings for cycling and the open air café; autumn for the forest colour', howToGet:'Tram 7 or 16 west to Vingis Park stop; or walk over the Mindaugas bridge and follow the river.', whatToAvoid:'Nothing specific', hiddennessScore:5, category:'Park', interests:['hiking','relaxation','photography'], lat:54.6831, lng:25.2400, address:'Vingis Park, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-lazdynai', name:'Lazdynai Housing Estate', city:'Vilnius', country:'Lithuania', shortDesc:'Soviet housing that won the Lenin Prize for architecture in 1974 — built into forested hills', fullDesc:'A 1960s–1970s housing estate in southwest Vilnius designed by Vytautas Čekanauskas and Vytautas Brėdikis, who won the Lenin Prize in 1974 for integrating mass housing into the natural landscape. The towers step down forested hillsides in a way that was genuinely radical. The estate is now a listed heritage area, one of the finest examples of Soviet urban design anywhere.', whyHidden:'In southwest Vilnius, far from tourist areas. Soviet housing estates are not obvious tourist destinations, but this one is architecturally extraordinary and historically significant.', bestTime:'Autumn when the forest around the buildings turns colour; overcast days for photography', howToGet:'Tram 11 or bus 5 from the city centre to Lazdynai terminus.', whatToAvoid:'Nothing specific — it is an active residential district', hiddennessScore:9, category:'Architecture', interests:['monuments','photography'], lat:54.6680, lng:25.2100, address:'Lazdynai, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-pavilniai-park', name:'Pavilniai Regional Park', city:'Vilnius', country:'Lithuania', shortDesc:'Wild river gorges, limestone outcrops and Pūčkoriai Hill inside the city limits', fullDesc:'A regional park covering the Vilnelė river gorges east of the city centre, with steep limestone and chalk outcrops, dense forest and dramatic viewpoints. Pūčkoriai Exposure, where the river cuts through a 10-metre chalk cliff, is the most striking geological site in Lithuania. Wolves and deer are sighted here despite being within Vilnius city limits.', whyHidden:'Vilnius is not associated with dramatic natural scenery. The park — 15 minutes by bus from the old city — contains landscapes that visitors to Iceland would photograph extensively.', bestTime:'Spring and autumn; morning fog in the valley is extraordinary', howToGet:'Bus 18 or 19 east from the old city to Pavilniai; follow the Vilnelė river upstream.', whatToAvoid:'Some trails are muddy after rain; proper footwear recommended', hiddennessScore:8, category:'Nature', interests:['hiking','photography','relaxation'], lat:54.6650, lng:25.3490, address:'Pavilniai Regional Park, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-belmontas', name:'Belmontas Valley', city:'Vilnius', country:'Lithuania', shortDesc:'A river gorge with a restored watermill, forest walks and an excellent restaurant — 20 minutes from the old city', fullDesc:'A narrow valley cut by the Vilnelė river, accessible by bicycle or bus, containing a restored 19th-century watermill complex with a good restaurant, forest footpaths along the riverbanks and views up to limestone cliff-tops. The valley feels entirely remote despite being within the city.', whyHidden:'Accessible only by bicycle or bus from the city centre — just enough friction. Vilnius residents know and love it; the valley appears on almost no tourist material.', bestTime:'Summer for the mill restaurant terrace; autumn for the forest colour along the river', howToGet:'Bicycle along the Vilnelė river cycle path from Užupis (30 minutes); or bus 34 to Belmontas.', whatToAvoid:'The restaurant requires booking at weekends', hiddennessScore:7, category:'Nature', interests:['hiking','relaxation','food'], lat:54.6540, lng:25.3300, address:'Belmontas, Vilnius', entryPrice:'Free (restaurant extra)', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-presidential-palace', name:'Presidential Palace Courtyard', city:'Vilnius', country:'Lithuania', shortDesc:'18th-century neoclassical palace — courtyard open to the public for free', fullDesc:'A neoclassical palace in the heart of the old city serving as the official residence and offices of the Lithuanian president. Napoleon slept here in 1812. The gates are regularly open during the day and visitors can enter the formal courtyard gardens. Free guided tours run on most Saturdays.', whyHidden:'The gates look closed and official, deterring most visitors. Free access is not advertised and the palace is rarely mentioned in tourist literature.', bestTime:'Saturday mornings when free guided tours are available', howToGet:'Walk along Daukanto square (Daukantas Square) directly opposite the main entrance on S. Daukanto aikštė 3.', whatToAvoid:'The interior is closed unless a tour is pre-booked', hiddennessScore:6, category:'Architecture', interests:['monuments','history','photography'], lat:54.6847, lng:25.2878, address:'S. Daukanto a. 3, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-tymo-market', name:'Tymo Turgus', city:'Vilnius', country:'Lithuania', shortDesc:'Artisan weekend market in Naujamiestis with Lithuanian natural wine, cheese and crafts', fullDesc:'A weekend artisan market in the Tymo district of Naujamiestis, occupying a courtyard behind a row of restored early 20th-century buildings. Producers sell fermented foods, natural wine from Lithuania and Georgia, artisan cheeses, smoked meats and handmade ceramics. The most focused food market in Vilnius.', whyHidden:'In Naujamiestis, a neighbourhood tourists rarely visit. The market is small and word-of-mouth; Vilnius locals come here specifically for natural wine and fermented food.', bestTime:'Saturday and Sunday 10am–4pm', howToGet:'Walk west from Gedimino prospect along Trakų gatvė to Tymo gatvė.', whatToAvoid:'Some vendors sell out of natural wine by noon on Saturdays', hiddennessScore:7, category:'Market', interests:['food','markets'], lat:54.6780, lng:25.2750, address:'Tymo g. 2, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-snekutis-pub', name:'Šnekutis', city:'Vilnius', country:'Lithuania', shortDesc:'Old Lithuanian village pub transplanted to the city — homemade bread, cold cuts, dark kvass', fullDesc:'A deliberately old-fashioned pub operating in a low-ceilinged wood-panelled room, serving only Lithuanian food — homemade dark rye bread, smoked pig ear, cottage cheese, pickled vegetables — and a small selection of Lithuanian beers and dark kvass. The atmosphere is entirely that of a pre-Soviet Lithuanian village tavern.', whyHidden:'On a residential side street in Žvėrynas, unmarked from outside. Frequented entirely by older Lithuanian men and Lithuanian food researchers.', bestTime:'Weekday afternoons 2–6pm', howToGet:'Walk across the Žvėrynas bridge and south to Užupio gatvė 2.', whatToAvoid:'No English menu; point and ask', hiddennessScore:8, category:'Food', interests:['food'], lat:54.6798, lng:25.2897, address:'Užupio g. 2, Vilnius', entryPrice:'Free entry', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-sweet-root', name:'Sweet Root', city:'Vilnius', country:'Lithuania', shortDesc:'Lithuania\'s most acclaimed restaurant — avant-garde Baltic cuisine from foraged ingredients', fullDesc:'A restaurant in a cellar near the Cathedral serving the most ambitious and critically acclaimed food in Lithuania. The menu focuses on foraged and fermented ingredients — birch sap, wood sorrel, smoked hay, fermented barley — transformed into a tasting menu that has drawn comparisons to Noma. Consistently among the best dining experiences in the Baltic states.', whyHidden:'In an unmarked basement near the Cathedral; no external signage. Requires advance booking weeks ahead. The avant-garde concept doesn\'t fit the standard Vilnius food narrative.', bestTime:'Dinner Tuesday–Saturday; book 3–4 weeks ahead', howToGet:'Walk to the Cathedral area; the restaurant is on Žygimantų gatvė.', whatToAvoid:'Walk-ins impossible; the tasting menu takes 3–4 hours', hiddennessScore:7, category:'Food', interests:['food'], lat:54.6869, lng:25.2851, address:'Žygimantų g. 1, Vilnius', entryPrice:'€70–100 tasting menu', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-loftas-venue', name:'Loftas', city:'Vilnius', country:'Lithuania', shortDesc:'Enormous converted factory turned concert hall — the heartbeat of Lithuanian independent music', fullDesc:'A vast converted factory in the Naujininkai district, south of the old city, operating as the main venue for independent music in Lithuania. The main hall holds 2000; smaller rooms run club nights. Major Lithuanian and international rock, metal and electronic acts play here. The building retains its industrial character completely.', whyHidden:'In Naujininkai, a southern district tourists never visit. The venue operates without tourist marketing — its audience is entirely Lithuanian.', bestTime:'Concert nights (check the programme online); weekend club nights from 10pm', howToGet:'Walk south from the old city bus station along Savanoriu prospect for 20 minutes; or bus 34.', whatToAvoid:'Ticket required for concerts — book in advance online', hiddennessScore:8, category:'Offbeat', interests:['nightlife','art'], lat:54.6620, lng:25.2540, address:'Švitrigailos g. 29, Vilnius', entryPrice:'Varies by event', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-verkiai-palace', name:'Verkiai Palace Ruins and Park', city:'Vilnius', country:'Lithuania', shortDesc:'18th-century bishop\'s palace on a forested hilltop — ruins with Neris valley views', fullDesc:'The ruins of a late 18th-century neoclassical summer palace built for the Bishops of Vilnius on a forested hilltop north of the city. The main hall is roofless but the colonnaded facade survives. The surrounding Verkiai Regional Park has birch forests, the Neris river valley and a network of trails to watermills and viewpoints.', whyHidden:'15km north of the city centre, requiring a bus. The scale of the ruins and the park\'s beauty are entirely unappreciated by visitors.', bestTime:'Early spring before foliage; autumn when the forest is red', howToGet:'Bus 36 from the city centre north to Verkiai; walk uphill 10 minutes through the park.', whatToAvoid:'Muddy after rain; some trails are poorly marked', hiddennessScore:9, category:'Nature', interests:['hiking','photography','monuments'], lat:54.7490, lng:25.3120, address:'Verkių g. 100, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-st-casimir-church', name:'Church of St. Casimir', city:'Vilnius', country:'Lithuania', shortDesc:'First Baroque church in Vilnius — 17th century, used as a museum of atheism under the Soviets', fullDesc:'Built by the Jesuits in 1618, the first Baroque church in Vilnius and one of the most significant. Its distinctive crown dome modelled on the Royal Castle chapel in Warsaw is unique in Lithuania. Under Soviet rule it served as a museum of atheism; it was returned to the Catholic Church in 1989 and the bullet holes from the Soviet storming are still visible.', whyHidden:'On Didžioji gatvė in the heart of the old city yet consistently overlooked in favour of the Cathedral. The history of its Soviet-era abuse makes it one of the most charged spaces in Vilnius.', bestTime:'Weekday mornings when the church is quiet', howToGet:'Walk along Didžioji gatvė from the Town Hall — the church is on the left.', whatToAvoid:'Closed during services on Sunday morning', hiddennessScore:5, category:'Architecture', interests:['monuments','history','photography'], lat:54.6793, lng:25.2884, address:'Didžioji g. 34, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-kalvariju-market', name:'Kalvarijų Turgus', city:'Vilnius', country:'Lithuania', shortDesc:'The largest outdoor market in Lithuania — everything from mushrooms to Soviet cameras', fullDesc:'A vast open-air market in the Žirmūnai district north of the city, operating on weekends as the largest market in Lithuania. Stalls cover several hectares selling fresh produce, dried mushrooms and berries from the forests, household goods, Soviet-era tools and cameras, clothing and live chickens. Entirely local, entirely Lithuanian.', whyHidden:'Requires a bus north of the city. The scale and character — Lithuanian grandmothers selling jars of pickled cucumbers next to Soviet camera dealers — is unlike anything in the tourist zone.', bestTime:'Saturday morning from 7am when the best produce arrives', howToGet:'Bus 35 or 36 north from the city centre to Kalvarijų g. 61.', whatToAvoid:'Closes by noon when the best stalls pack up', hiddennessScore:8, category:'Market', interests:['markets','food','photography'], lat:54.7070, lng:25.2940, address:'Kalvarijų g. 61, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-paupys-neighbourhood', name:'Paupys', city:'Vilnius', country:'Lithuania', shortDesc:'New neighbourhood behind Užupis — old industrial buildings turned into the best weekend food market', fullDesc:'A new mixed-use neighbourhood developed in a former industrial zone behind Užupis, with a weekend food market in a converted factory courtyard, independent coffee shops, design studios and riverside walks. The contrast with the medieval old city 200 metres away is extraordinary. The market is the best in Vilnius for street food.', whyHidden:'A few hundred metres from Užupis but requires knowing the entrance. The neighbourhood doesn\'t yet appear on most maps.', bestTime:'Weekend market Saturday–Sunday 10am–4pm', howToGet:'Walk through Užupis and continue east along the river; or enter from Bernardinų gatvė.', whatToAvoid:'Nothing on weekdays — most spaces are closed', hiddennessScore:6, category:'Neighbourhood', interests:['food','markets','photography'], lat:54.6792, lng:25.2974, address:'Paupys, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-energetika-museum', name:'Energetika Museum', city:'Vilnius', country:'Lithuania', shortDesc:'Soviet-era power equipment preserved in a working 1963 electrical substation', fullDesc:'The Energetika Museum preserves the original equipment from a 1963 electrical substation — transformers, switchboards, meters, turbine components — exactly as they were operated until the 1990s. The collection documents the electrification of Soviet Lithuania. One of the most unusual industrial heritage museums in the Baltics.', whyHidden:'In the Naujoji Vilnia district, far northeast of the city. The subject matter ensures it stays entirely off tourist radars.', bestTime:'Any weekday', howToGet:'Train from Vilnius station to Naujoji Vilnia, walk 10 minutes to the museum.', whatToAvoid:'Closed weekends; check opening hours in advance', hiddennessScore:9, category:'Museum', interests:['museums','unusual','history'], lat:54.7107, lng:25.3249, address:'Šilo g. 6, Naujoji Vilnia, Vilnius', entryPrice:'€3', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-sapieha-palace', name:'Sapiegų Palace and Park', city:'Vilnius', country:'Lithuania', shortDesc:'17th-century Baroque palace and English landscape garden — in a residential suburb, zero visitors', fullDesc:'A large Baroque palace built by the Sapieha magnate family in the 1690s, now partially restored and surrounded by an 18th-century English landscape park. The palace was ransacked by Peter the Great\'s troops in 1708 and used as a barracks for much of its history; the current restoration is ongoing. The park has a large lake and century-old trees.', whyHidden:'In the Antakalnis residential district, 3km from the old city. No tourist infrastructure; the palace is being restored without fanfare.', bestTime:'Autumn for the park colour; spring when the lake reflects the palace facade', howToGet:'Walk from St. Peter and Paul Church north along Antakalnio gatvė; the palace is on Antakalnio g. 56.', whatToAvoid:'Interior access is limited during ongoing restoration', hiddennessScore:8, category:'Architecture', interests:['monuments','photography'], lat:54.7010, lng:25.2842, address:'Antakalnio g. 56, Vilnius', entryPrice:'Free (park)', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-mickiewicz-memorial', name:'Adam Mickiewicz Apartment', city:'Vilnius', country:'Lithuania', shortDesc:'The room where Poland\'s greatest poet lived as a student — preserved as a literary memorial', fullDesc:'A small apartment on Bernardinų gatvė where the Polish romantic poet Adam Mickiewicz (known in Lithuanian as Adomas Mickevičius) lived as a student at Vilnius University from 1815 to 1819. The rooms are preserved with period furniture and manuscripts. Mickiewicz went on to write Pan Tadeusz, the national epic of Poland, which opens in Vilnius.', whyHidden:'Vilnius is a city both Poland and Lithuania claim as part of their literary heritage; this apartment represents the intersection. It is overlooked by tourists who know neither the Polish nor the Lithuanian dimension.', bestTime:'Any weekday', howToGet:'Walk along Bernardinų gatvė from St. Anne\'s Church; the apartment is at number 11.', whatToAvoid:'Closed Monday', hiddennessScore:7, category:'Museum', interests:['museums','history'], lat:54.6825, lng:25.2933, address:'Bernardinų g. 11, Vilnius', entryPrice:'€2', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-trinitarian-tower', name:'Trinitarian Tower View', city:'Vilnius', country:'Lithuania', shortDesc:'The highest point in the old city — panoramic view from a restored defensive tower', fullDesc:'A defensive tower on the western edge of the old city, now accessible via a restored staircase, with a view across the rooftops and the Neris river valley to the west. Unlike Gediminas Castle, the Trinitarian Tower is almost never mentioned in tourist literature despite offering an equally fine view from a different angle.', whyHidden:'The tower entrance is on a quiet lane with no tourist signage. Gediminas Castle absorbs all the viewpoint tourism.', bestTime:'Clear mornings; golden hour for the warm light on the old city roofline', howToGet:'Walk along Kauno gatvė from the old city edge; follow signs for the Trinitarian Tower.', whatToAvoid:'Irregular opening hours — check in advance', hiddennessScore:7, category:'Architecture', interests:['monuments','photography'], lat:54.6785, lng:25.2820, address:'Lydos g. 1, Vilnius', entryPrice:'€3', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-green-bridge', name:'Green Bridge Soviet Sculptures', city:'Vilnius', country:'Lithuania', shortDesc:'Four Socialist Realist statue groups from 1952 — the last in situ in any EU capital', fullDesc:'The Green Bridge (Žaliasis tiltas) crossing the Neris was flanked by four groups of Socialist Realist bronze figures from 1952 — soldiers, farmers, students and workers in heroic poses. Despite campaigns to remove them, they remain in place, now repurposed as historical artefacts. They are the only large-scale Socialist Realist public sculptures remaining in situ in any EU capital city.', whyHidden:'The bridge is on the tourist route from the new town to the old city, but most visitors cross without looking at the sculptural groups at each corner.', bestTime:'Any day — accessible 24 hours', howToGet:'Walk north from the Cathedral along Gedimino prospect to the Neris; cross the Green Bridge.', whatToAvoid:'Nothing — the statues are on the bridge parapets', hiddennessScore:5, category:'Architecture', interests:['monuments','history','photography'], lat:54.6934, lng:25.2843, address:'Žaliasis tiltas, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-naujoji-vilnia-dainos', name:'Dainos Hill (Dainų Kalnas)', city:'Vilnius', country:'Lithuania', shortDesc:'Soviet-era outdoor song festival terraces on a forested hill — the Baltic singing tradition made concrete', fullDesc:'A vast amphitheatre cut into a forested hillside in the Naujoji Vilnia district, used for the Soviet-era Lithuanian Song Celebrations that were co-opted into the independence movement. The terrace seats 30,000. Empty on ordinary days, the scale of the stone-and-grass terraces in the forest is extraordinary and unlike anything in Western Europe.', whyHidden:'In the far northeast of the city, difficult to reach without a car. The Baltic Song Celebrations that played a critical role in independence are poorly known outside the Baltic states.', bestTime:'Any clear day; the hill has views of the Neris valley', howToGet:'Suburban train to Naujoji Vilnia, walk south up Dainų Kalnas.', whatToAvoid:'No infrastructure — bring water', hiddennessScore:9, category:'Architecture', interests:['monuments','unusual','photography'], lat:54.7094, lng:25.3203, address:'Dainų Kalnas, Naujoji Vilnia, Vilnius', entryPrice:'Free', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-cathedral-crypt', name:'Vilnius Cathedral Royal Crypt', city:'Vilnius', country:'Lithuania', shortDesc:'Medieval underground crypt with tombs of Lithuanian Grand Dukes — rarely visited', fullDesc:'Below Vilnius Cathedral lies a series of medieval crypts accessible on guided tours, containing the remains of several Lithuanian Grand Dukes and other historical figures. The 2001 discovery of what is believed to be the tomb of Grand Duchess Barbara Radziwiłł added a new chapter to the site. The crypts represent the burial centre of the medieval Grand Duchy of Lithuania.', whyHidden:'Tours must be booked in advance and the entrance is unmarked inside the cathedral. Most visitors see the cathedral interior but never descend to the crypts.', bestTime:'Any day — pre-book a guided tour at the cathedral desk', howToGet:'Enter Vilnius Cathedral on Cathedral Square; book the crypt tour at the information desk inside.', whatToAvoid:'The crypt is cold year-round — bring a layer', hiddennessScore:6, category:'Museum', interests:['museums','history'], lat:54.6862, lng:25.2908, address:'Katedros a. 1, Vilnius', entryPrice:'€5 guided tour', photo:'1517154421773-0855bef3fd1b' },
  { id:'vilnius-cathedral-bell-tower', name:'Cathedral Bell Tower', city:'Vilnius', country:'Lithuania', shortDesc:'Medieval defensive tower repurposed as a cathedral bell tower — separate from the cathedral, climbable', fullDesc:'A 15th-century defensive tower on the edge of Cathedral Square that was converted into a bell tower for the cathedral. Unlike the cathedral itself, the bell tower can be climbed independently via a narrow staircase, offering rooftop views of the Cathedral, Gediminas Hill and the old city to the south. One of the best viewpoints in Vilnius.', whyHidden:'Tourists photograph the cathedral from outside but few notice the tower is climbable. Admission is from the cathedral ticket office on the south side.', bestTime:'Morning for the best light on the Cathedral facade', howToGet:'Enter via the small door on the south side of the tower, facing the Cathedral.', whatToAvoid:'The staircase is very steep and narrow — not suitable for those with mobility issues', hiddennessScore:5, category:'Architecture', interests:['monuments','photography'], lat:54.6864, lng:25.2902, address:'Katedros a. 2, Vilnius', entryPrice:'€4', photo:'1517154421773-0855bef3fd1b' },
  { id: 'vilnius-uzupis-republic', name: 'Užupis Republic Art District', city: 'Vilnius', country: 'Lithuania', shortDesc: 'The self-declared independent republic in the heart of Vilnius — constitution on a wall', fullDesc: 'Užupis is a bohemian neighbourhood across the Vilnia River that declared independence as the "Republic of Užupis" on April 1, 1997. It has its own constitution (carved on mirrors in multiple languages on a wall), a president, a bishop, and an army of 11 men. The neighbourhood is home to artists and galleries and the annual April 1 celebration is extraordinary.', whyHidden: 'Well known to Vilnius visitors but almost never understood. The constitution wall (Paupio gatve) lists rights including "the right to be a dog" and "the right to be unhappy." Reading it in full is the required Vilnius experience.', bestTime: 'April 1 for the independence celebrations; any other day for the gallery trail', howToGet: 'Walk from the Old Town over the Užupis Bridge.', whatToAvoid: 'The neighbourhood is very small — it can be explored in an hour; combine with the Old Town', hiddennessScore: 4, category: 'Neighbourhood', interests: ['neighbourhood', 'art', 'unusual'], lat: 54.6815, lng: 25.2938, address: 'Užupis, Vilnius', entryPrice: 'Free', photo: '1528727548-8e814d0cb3a2' },

  { id: 'vilnius-bernardine-cemetery', name: 'Bernardine Cemetery', city: 'Vilnius', country: 'Lithuania', shortDesc: 'The most romantic cemetery in the Baltic States — Romantic-era sculpture and forest setting', fullDesc: 'The Bernardine Cemetery east of the Old Town is the most atmospheric cemetery in Vilnius — Romantic-period cast-iron monuments, classical columns, weeping willows and graves from 1810 to the present. The cemetery was established in 1810 and fell into disrepair during the Soviet period; recent restoration has preserved the most significant monuments.', whyHidden: 'East of the Old Town, requiring a deliberate visit. The 19th-century funerary sculpture and the forest setting are extraordinary.', bestTime: 'Morning any day; autumn for the forest atmosphere', howToGet: 'Walk from the Old Town east past the Church of St Anne.', whatToAvoid: 'Parts of the cemetery have not been fully restored — watch for uneven ground', hiddennessScore: 7, category: 'History', interests: ['history', 'art', 'unusual'], lat: 54.6821, lng: 25.2947, address: 'Rasų g. 2, Vilnius', entryPrice: 'Free', photo: '1495435898-33d8e1a25032' },

  { id: 'vilnius-market-hales', name: 'Halės Market (Hales turgus)', city: 'Vilnius', country: 'Lithuania', shortDesc: 'Vilnius\'s main covered market since 1906 — local produce, Soviet-era stalls', fullDesc: 'Halės Market occupies an Art Nouveau metal-and-glass hall from 1906 with a grid of stalls selling local Lithuanian produce, pickled mushrooms, smoked cheese, rye bread, amber, and Soviet-era memorabilia. The market is entirely used by Vilnius residents and has remained largely unchanged from the Soviet period in terms of its social function.', whyHidden: 'Adjacent to the Old Town but not on tourist maps. The market is Vilnius\'s daily food hub and gives an accurate picture of Lithuanian food culture.', bestTime: 'Saturday mornings from 7am for the widest selection', howToGet: 'Walk from the Gates of Dawn southward to Pylimo gatvė.', whatToAvoid: 'Closed Sunday afternoon and Monday morning', hiddennessScore: 6, category: 'Market', interests: ['market', 'food', 'history'], lat: 54.6742, lng: 25.2840, address: 'Pylimo g. 58, Vilnius', entryPrice: 'Free', photo: '1555041469-db61523df9a4' },

  { id: 'vilnius-antokolnis-neighbourhood', name: 'Antakalnis Neighbourhood and Soviet Monuments', city: 'Vilnius', country: 'Lithuania', shortDesc: 'Vilnius\'s green neighbourhood — Soviet memorial complex, Paneriai forest, river swimming', fullDesc: 'Antakalnis is the forested neighbourhood east of the Old Town with the Soviet-era Tuskulėnai Memorial Complex (mass graves of NKVD victims), the extraordinary Tuskulėnai Manor Park, and access to the Neris River swimming spots. A completely different Vilnius from the Old Town tourist district.', whyHidden: 'East of the Old Town, requiring a bus journey. The Soviet memorial complex is one of the most historically significant sites in Lithuania and almost no tourists visit.', bestTime: 'Morning any day; summer for the river swimming', howToGet: 'Bus 7 or 40 from the Old Town to Antakalnis.', whatToAvoid: 'The Tuskulėnai memorial is not appropriate for children — it deals with mass executions during the Soviet occupation', hiddennessScore: 8, category: 'History', interests: ['history', 'park', 'unusual'], lat: 54.7000, lng: 25.3060, address: 'Antakalnis, Vilnius', entryPrice: 'Free', photo: '1594736797933-d0501ba2fe65' },

  { id: 'vilnius-frankonian-quarter', name: 'Šnipiškės Neighbourhood (Former Jewish Quarter)', city: 'Vilnius', country: 'Lithuania', shortDesc: 'The neighbourhood of the old Vilna Ghetto — where Jewish Vilnius was before 1941', fullDesc: 'Before WWII, Vilnius (Vilna in Yiddish) was known as the "Jerusalem of Lithuania" — a major Jewish cultural centre with over 100 synagogues and a population of over 100,000 Jews. The neighbourhood of Šnipiškės and the Old Town Ghetto were the heart of this world. Almost nothing survives, but the street plan of the ghetto is intact and documented in a self-guided walking trail.', whyHidden: 'The Choral Synagogue and the memorial plaques are not prominently promoted. The documentation trail is available from the Vilna Gaon Jewish State Museum.', bestTime: 'Any day; the museum opens Tuesday–Sunday 9am–5pm', howToGet: 'Walk from the Town Hall through the Old Town ghetto area.', whatToAvoid: 'Most physical evidence was destroyed — the memorial experience requires context from the museum', hiddennessScore: 6, category: 'History', interests: ['history', 'spiritual', 'neighbourhood'], lat: 54.6824, lng: 25.2804, address: 'Žydų g., Vilnius Old Town', entryPrice: 'Free (Museum €4)', photo: '1514782458655-a1c7d879a6e1' },

  { id: 'vilnius-gediminas-tower-dawn', name: 'Gediminas Tower at Dawn', city: 'Vilnius', country: 'Lithuania', shortDesc: 'The ruined 14th-century Lithuanian castle at sunrise — 360 panorama, alone', fullDesc: 'Gediminas Tower is the surviving remnant of the 14th-century Upper Castle of Vilnius, sitting on a 48-metre hill above the Old Town. At sunrise — before 8am — the tower is empty (it opens at 10am) but the hilltop is accessible via the footpath. The 360-degree panorama from the hilltop — over the Old Town churches, Užupis and the green hills of Lithuania beyond — is extraordinary.', whyHidden: 'The tower is a tourist destination during the day. The hilltop at sunrise, accessed via the footpath before the museum opens, is a completely different experience.', bestTime: 'Sunrise any day', howToGet: 'Walk up the footpath from Arsenalo Street or from Kathedros Square.', whatToAvoid: 'The tower interior museum is only open from 10am; the hilltop is accessible earlier', hiddennessScore: 4, category: 'History', interests: ['history', 'architecture', 'nature'], lat: 54.6867, lng: 25.2912, address: 'Gedimino pilies g. 4, Vilnius', entryPrice: 'Free (hilltop); tower €6', photo: '1467218504634-7f7519dc8b85' },

  { id: 'vilnius-vilnius-university-courtyards', name: 'Vilnius University Courtyard Network', city: 'Vilnius', country: 'Lithuania', shortDesc: 'Founded 1579 — the interconnected courtyard network of the oldest university in the Baltics', fullDesc: 'Vilnius University (founded 1579) occupies an entire city block in the Old Town and has 13 interconnected courtyards connected by passageways. The Great Courtyard, the Observatory (one of the few Baroque observatories in Europe), and the Grand Library atrium can all be entered freely during university hours. The fresco cycle in the Great Courtyard (1776) is outstanding.', whyHidden: 'The university entrances are not obviously marked. Walking through the courtyard sequence — from the main entrance to the observatory — takes 20 minutes and is entirely free.', bestTime: 'Weekday daytime when university is in session (September–June)', howToGet: 'Walk from Cathedral Square through the Old Town to Universiteto gatvė.', whatToAvoid: 'Closed in the main summer vacation period (July–August); the observatory has irregular opening hours', hiddennessScore: 5, category: 'Architecture', interests: ['architecture', 'history', 'art'], lat: 54.6844, lng: 25.2876, address: 'Universiteto g. 3, Vilnius', entryPrice: 'Free (daytime)', photo: '1528727548-8e814d0cb3a2' },
];
